import React from 'react';
import { NavLink } from 'react-router-dom';
import {
  LayoutDashboard,
  Clock,
  CalendarDays,
  DollarSign,
  CalendarCheck,
  History,
  Bot,
} from 'lucide-react';

const navItems = [
  { to: '/dashboard',              icon: LayoutDashboard, label: 'Overview',      end: true },
  { to: '/dashboard/time-tracking',icon: Clock,           label: 'Time Tracking'         },
  { to: '/dashboard/schedule',     icon: CalendarDays,    label: 'Schedule'              },
  { to: '/dashboard/salary',       icon: DollarSign,      label: 'Salary'                },
  { to: '/dashboard/leave',        icon: CalendarCheck,   label: 'Leave'                 },
  { to: '/dashboard/history',      icon: History,         label: 'History'               },
  { to: '/dashboard/ai-assistant', icon: Bot,             label: 'AI Assistant'          },
];

export function Sidebar() {
  return (
    <aside className="fixed left-0 top-0 h-screen w-[240px] bg-dash-sidebar border-r border-dash-border flex flex-col z-40 transition-colors duration-200">
      {/* Logo */}
      <div className="h-14 flex items-center px-6 border-b border-dash-border">
        <a href="/" className="flex items-center gap-2">
          <div className="w-7 h-7 rounded-md bg-dash-primary flex items-center justify-center">
            <span className="text-white" style={{ fontSize: '12px', fontWeight: 700 }}>C</span>
          </div>
          <span className="text-dash-text tracking-tight" style={{ fontSize: '18px', fontWeight: 700 }}>
            Chain
          </span>
        </a>
      </div>

      {/* Navigation */}
      <nav className="flex-1 py-3 px-3 space-y-0.5 overflow-y-auto">
        <p className="px-3 pt-2 pb-2 text-dash-text-muted uppercase tracking-wider" style={{ fontSize: '10px', fontWeight: 600 }}>
          Menu
        </p>
        {navItems.map((item) => (
          <NavLink
            key={item.to}
            to={item.to}
            end={item.end}
            className={({ isActive }) =>
              `relative flex items-center gap-3 px-3 py-2 rounded-md transition-colors duration-150 ${
                isActive
                  ? 'bg-dash-primary-light text-dash-primary'
                  : 'text-dash-text-secondary hover:bg-dash-sidebar-hover hover:text-dash-text'
              }`
            }
          >
            {({ isActive }) => (
              <>
                {isActive && (
                  <div className="absolute left-0 top-1.5 bottom-1.5 w-[3px] rounded-r-sm bg-dash-primary" />
                )}
                <item.icon size={18} strokeWidth={isActive ? 2 : 1.5} className="shrink-0" />
                <span style={{ fontSize: '13px', fontWeight: isActive ? 500 : 400 }}>
                  {item.label}
                </span>
              </>
            )}
          </NavLink>
        ))}
      </nav>

      {/* Footer */}
      <div className="px-4 py-3 border-t border-dash-border">
        <p className="text-dash-text-muted" style={{ fontSize: '11px' }}>
          Chain HR Platform v1.0
        </p>
      </div>
    </aside>
  );
}
